input.commands:
set -e
cat /tmp/both.json | jq -r '
  def pct($new; $old): if $old==0 then null else ((($new-$old)/$old)*100) end;
  def fmtPct($x): if $x==null then "n/a" else ($x|sprintf("%.2f%%")) end;
  def fmtNum($x):
    if ($x|type)=="number" then
      (if ($x<1 and $x>0) then ($x|sprintf("%.3f")) else ($x|tostring) end)
    else ($x|tostring) end;
  . as $b |
  [
    {m:"page_views", a:$b.d14.page_views, b:$b.d15.page_views},
    {m:"unique_visitors", a:$b.d14.unique_visitors, b:$b.d15.unique_visitors},
    {m:"bounce_rate", a:$b.d14.bounce_rate, b:$b.d15.bounce_rate},
    {m:"avg_session_duration", a:$b.d14.avg_session_duration, b:$b.d15.avg_session_duration},
    {m:"conversion_rate", a:$b.d14.conversion_rate, b:$b.d15.conversion_rate}
  ]
  | ( ["metric","2025-12-14","2025-12-15","% change","anomaly (>20%)"] | @tsv ),
    ( .[] |
      (.b as $new | .a as $old | pct($new;$old) as $p |
        [ .m, fmtNum($old), fmtNum($new), fmtPct($p), (if ($p|abs)>20 then "YES" else "" end) ] | @tsv )
    )
'

